=<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8" />
  <title>Live Agent Dashboard</title>
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
</head>
<body>
  <div class="container">
    <header>
      <h1>🎧 Live Agent Dashboard</h1>
      <p class="subtitle">Pending Customer Messages</p>
    </header>

    <div class="stats">
      <div class="stat-card">
        <span class="stat-number">{{ $json.length || 0 }}</span>
        <span class="stat-label">Pending Messages</span>
      </div>
    </div>

    <div class="messages-container">
      {{ $json.length === 0 ? '<div class="no-messages"><p>✅ No pending messages</p><p class="subtitle">All caught up!</p></div>' : '' }}

      {{ $json.map((msg, index) => `
        <div class="message-card" id="message-${msg.id}">
          <div class="message-header">
            <span class="session-id">Session: ${msg.session_id}</span>
            <span class="timestamp">${new Date(msg.created_at).toLocaleString()}</span>
          </div>
          <div class="message-content">
            <p>${msg.message}</p>
          </div>
          <div class="reply-section">
            <textarea 
              id="reply-${msg.id}" 
              class="reply-input" 
              placeholder="Type your reply here..."
              rows="3"
            ></textarea>
            <button 
              class="send-btn" 
              onclick="sendReply(${msg.id}, '${msg.session_id}')"
            >
              Send Reply
            </button>
          </div>
        </div>
      `).join('') }}
    </div>

    <div class="refresh-info">
      <p>Auto-refreshing every 10 seconds</p>
      <button class="refresh-btn" onclick="location.reload()">🔄 Refresh Now</button>
    </div>
  </div>
</body>
</html>

<style>
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  min-height: 100vh;
  padding: 20px;
}

.container {
  max-width: 1200px;
  margin: 0 auto;
}

header {
  text-align: center;
  color: white;
  margin-bottom: 30px;
}

header h1 {
  font-size: 36px;
  font-weight: bold;
  margin-bottom: 10px;
}

header .subtitle {
  font-size: 18px;
  opacity: 0.9;
}

.stats {
  display: flex;
  justify-content: center;
  margin-bottom: 30px;
}

.stat-card {
  background: white;
  padding: 20px 40px;
  border-radius: 12px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  display: flex;
  flex-direction: column;
  align-items: center;
}

.stat-number {
  font-size: 48px;
  font-weight: bold;
  color: #667eea;
}

.stat-label {
  font-size: 14px;
  color: #666;
  margin-top: 5px;
}

.messages-container {
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.message-card {
  background: white;
  border-radius: 12px;
  padding: 20px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  transition: transform 0.2s;
}

.message-card:hover {
  transform: translateY(-2px);
  box-shadow: 0 6px 12px rgba(0, 0, 0, 0.15);
}

.message-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 15px;
  padding-bottom: 10px;
  border-bottom: 2px solid #f0f0f0;
}

.session-id {
  font-weight: bold;
  color: #667eea;
  font-size: 14px;
}

.timestamp {
  font-size: 12px;
  color: #999;
}

.message-content {
  margin-bottom: 15px;
}

.message-content p {
  font-size: 16px;
  line-height: 1.6;
  color: #333;
}

.reply-section {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.reply-input {
  width: 100%;
  padding: 12px;
  border: 2px solid #e0e0e0;
  border-radius: 8px;
  font-size: 14px;
  font-family: inherit;
  resize: vertical;
  transition: border-color 0.2s;
}

.reply-input:focus {
  outline: none;
  border-color: #667eea;
}

.send-btn {
  align-self: flex-end;
  padding: 12px 24px;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
  border: none;
  border-radius: 8px;
  font-size: 14px;
  font-weight: bold;
  cursor: pointer;
  transition: transform 0.2s, box-shadow 0.2s;
}

.send-btn:hover {
  transform: translateY(-2px);
  box-shadow: 0 4px 8px rgba(102, 126, 234, 0.4);
}

.send-btn:active {
  transform: translateY(0);
}

.no-messages {
  background: white;
  border-radius: 12px;
  padding: 60px 20px;
  text-align: center;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
}

.no-messages p {
  font-size: 24px;
  color: #333;
  margin-bottom: 10px;
}

.no-messages .subtitle {
  font-size: 16px;
  color: #999;
}

.refresh-info {
  text-align: center;
  margin-top: 30px;
  color: white;
}

.refresh-info p {
  margin-bottom: 10px;
  opacity: 0.9;
}

.refresh-btn {
  padding: 10px 20px;
  background: white;
  color: #667eea;
  border: none;
  border-radius: 8px;
  font-size: 14px;
  font-weight: bold;
  cursor: pointer;
  transition: transform 0.2s;
}

.refresh-btn:hover {
  transform: scale(1.05);
}

.success-message {
  position: fixed;
  top: 20px;
  right: 20px;
  background: #4caf50;
  color: white;
  padding: 15px 20px;
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.2);
  animation: slideIn 0.3s ease-out;
  z-index: 1000;
}

@keyframes slideIn {
  from {
    transform: translateX(400px);
    opacity: 0;
  }
  to {
    transform: translateX(0);
    opacity: 1;
  }
}

@media (max-width: 768px) {
  header h1 {
    font-size: 28px;
  }

  .message-card {
    padding: 15px;
  }
}
</style>

<script>
const WEBHOOK_BASE_URL = 'https://snake-test.app.n8n.cloud/webhook';

async function sendReply(messageId, sessionId) {
  const replyInput = document.getElementById(`reply-${messageId}`);
  const reply = replyInput.value.trim();

  if (!reply) {
    alert('Please enter a reply');
    return;
  }

  try {
    const response = await fetch(`${WEBHOOK_BASE_URL}/agent-reply`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        messageId: messageId,
        sessionId: sessionId,
        reply: reply
      })
    });

    if (response.ok) {
      showSuccessMessage('Reply sent successfully!');

      // Remove the message card from view
      const messageCard = document.getElementById(`message-${messageId}`);
      messageCard.style.transition = 'opacity 0.3s, transform 0.3s';
      messageCard.style.opacity = '0';
      messageCard.style.transform = 'translateX(100px)';

      setTimeout(() => {
        messageCard.remove();

        // Check if there are no more messages
        const messagesContainer = document.querySelector('.messages-container');
        if (messagesContainer.children.length === 0) {
          location.reload();
        }
      }, 300);
    } else {
      alert('Failed to send reply. Please try again.');
    }
  } catch (error) {
    console.error('Error sending reply:', error);
    alert('Error sending reply. Please check your connection.');
  }
}

function showSuccessMessage(message) {
  const successDiv = document.createElement('div');
  successDiv.className = 'success-message';
  successDiv.textContent = message;
  document.body.appendChild(successDiv);

  setTimeout(() => {
    successDiv.style.opacity = '0';
    setTimeout(() => successDiv.remove(), 300);
  }, 3000);
}

// Auto-refresh every 10 seconds
setInterval(() => {
  location.reload();
}, 10000);

console.log('Live Agent Dashboard loaded');
</script>
